module sr_flip_flop (
    input wire clk,
    input wire S,
    input wire R,
    output reg Q,
    output wire Qbar
);
    assign Qbar = ~Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (S && R)
            Q <= 0;  // Invalid state
        else if (S)
            Q <= 1;  // Set state
        else if (R)
            Q <= 0;  // Reset state
        // Else Q retains its previous state
    end
endmodule
